import React, { useState } from "react";
import { createUserWithEmailAndPassword } from "firebase/auth";
import { collection, query, where, getDocs, doc, setDoc } from "firebase/firestore";
import { auth, db } from "../firebase";
import Swal from "sweetalert2";
import { useNavigate } from "react-router-dom";
import "./Login.css"; // mantém o mesmo estilo visual do Login

function Cadastro() {
  const [nome, setNome] = useState("");
  const [email, setEmail] = useState("");
  const [cpf, setCpf] = useState("");
  const [senha, setSenha] = useState("");
  const [confirmarSenha, setConfirmarSenha] = useState("");
  const [carregando, setCarregando] = useState(false);

  const navigate = useNavigate();

  const handleCadastro = async (e) => {
    e.preventDefault();
    setCarregando(true);

    // Validação básica
    if (!nome || !email || !cpf || !senha || !confirmarSenha) {
      Swal.fire("Atenção", "Preencha todos os campos!", "warning");
      setCarregando(false);
      return;
    }

    if (senha !== confirmarSenha) {
      Swal.fire("Erro", "As senhas não conferem!", "error");
      setCarregando(false);
      return;
    }

    try {
      // Verifica se email ou CPF já existem
      const qEmail = query(collection(db, "usuarios"), where("email", "==", email));
      const qCpf = query(collection(db, "usuarios"), where("cpf", "==", cpf));

      const [snapEmail, snapCpf] = await Promise.all([
        getDocs(qEmail),
        getDocs(qCpf),
      ]);

      if (!snapEmail.empty) {
        Swal.fire("Erro", "Este e-mail já está cadastrado!", "error");
        setCarregando(false);
        return;
      }

      if (!snapCpf.empty) {
        Swal.fire("Erro", "Este CPF já está cadastrado!", "error");
        setCarregando(false);
        return;
      }

      // Cria o usuário no Firebase Authentication
      const userCredential = await createUserWithEmailAndPassword(auth, email, senha);
      const user = userCredential.user;

      // Salva os dados na coleção "usuarios" com o mesmo UID do Auth
      await setDoc(doc(db, "usuarios", user.uid), {
        uid: user.uid,
        nome,
        email,
        cpf,
        role: "morador",     // padrão
        ativo: false,        // aguardando aprovação do admin
        dataCadastro: new Date(),
      });

      Swal.fire(
        "Cadastro realizado!",
        "Seu cadastro foi enviado para aprovação do administrador.",
        "success"
      );

      navigate("/login");
    } catch (erro) {
      console.error("Erro ao cadastrar:", erro);
      let mensagemErro = "Não foi possível realizar o cadastro.";
      if (erro.code === "auth/email-already-in-use") mensagemErro = "Este e-mail já está em uso.";
      if (erro.code === "auth/weak-password") mensagemErro = "A senha deve ter pelo menos 6 caracteres.";

      Swal.fire("Erro", mensagemErro, "error");
    } finally {
      setCarregando(false);
    }
  };

  return (
    <div className="login-container">
      <h2>Cadastro</h2>
      <form onSubmit={handleCadastro}>
        <input
          type="text"
          placeholder="Nome completo"
          value={nome}
          onChange={(e) => setNome(e.target.value)}
        />
        <input
          type="email"
          placeholder="E-mail"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />
        <input
          type="text"
          placeholder="CPF"
          value={cpf}
          onChange={(e) => setCpf(e.target.value)}
        />
        <input
          type="password"
          placeholder="Senha"
          value={senha}
          onChange={(e) => setSenha(e.target.value)}
        />
        <input
          type="password"
          placeholder="Confirmar senha"
          value={confirmarSenha}
          onChange={(e) => setConfirmarSenha(e.target.value)}
        />

        <button type="submit" disabled={carregando}>
          {carregando ? "Enviando..." : "Cadastrar"}
        </button>
      </form>

      <p>
        Já tem uma conta?{" "}
        <span className="link" onClick={() => navigate("/login")}>
          Entrar
        </span>
      </p>
    </div>
  );
}

export default Cadastro;
